mapper.select:
/* intmInsrMapper.getIntmInsrOrder */
SELECT  CONTRACT_NUM    AS contractNum
        , INSR_PROD_CD  AS insrProdCd
        , INSR_STAT_CD  AS insrStatCd
        , MODEL_ID      AS modelId
        , INTM_SRL_NO   AS intmSrlNo
FROM    MSP_INTM_INSR_ORDER
WHERE   CONTRACT_NUM = #{contractNum}
AND     INSR_PROD_CD = #{insrProdCd}
AND     STRT_DTTM = #{strtDttm}
AND     END_DTTM = #{endDttm}

/* intmInsrMapper.getOpenModelInfo */
SELECT  TRIM(SUBSTR(FST_MODEL_INFO, 1, 20))     AS modelId
        , TRIM(SUBSTR(FST_MODEL_INFO, 21, 30))  AS modelNm
        , TRIM(SUBSTR(FST_MODEL_INFO, 51, 30))  AS intmSrlNo
FROM    MSP_REQUEST_DTL
WHERE   CONTRACT_NUM = #{contractNum}

