    , CLAUSE_FLAG
    , REGST_ID
    , REGST_DTTM
    , RVISN_ID
    , RVISN_DTTM
    , REQ_IN_DAY
) VALUES (
    #{contractNum, jdbcType=VARCHAR}
    , #{insrProdCd, jdbcType=VARCHAR}
    , #{strtDttm, jdbcType=VARCHAR}
    , #{endDttm, jdbcType=VARCHAR}
    , #{ifTrgtCd, jdbcType=VARCHAR}
    , #{insrStatCd, jdbcType=VARCHAR}
    , #{chnCd, jdbcType=VARCHAR}
    , #{insrEvntCd, jdbcType=VARCHAR}
    , #{reqBuyType, jdbcType=VARCHAR}
    , #{openDt, jdbcType=VARCHAR}
    , #{dvcChgDt, jdbcType=VARCHAR}
    , #{modelNm, jdbcType=VARCHAR}
    , #{modelId, jdbcType=VARCHAR}
    , #{intmSrlNo, jdbcType=VARCHAR}
    , #{imgChkYn, jdbcType=VARCHAR}
    , #{vrfyRsltCd, jdbcType=VARCHAR}
    , #{clauseFlag, jdbcType=VARCHAR}
    , 'BATCH'
    , SYSDATE
    , 'BATCH'
    , SYSDATE
    , #{reqInDay, jdbcType=VARCHAR}
)

mapper.select:
/* intmInsrMapper.getIntmInsrMember */
SELECT  INSR_MEMBER_NUM
		, (	
			SELECT	CD_DSC
			FROM   	CMN_GRP_CD_MST
			WHERE  	GRP_ID = 'CMN0247'
			AND    	CD_VAL = INSR_PROD_CD
		) AS INSR_PROD_NM
FROM    MSP_INTM_INSR_MEMBER
WHERE   CONTRACT_NUM = #{contractNum}
AND     INSR_PROD_CD = #{insrProdCd}
AND     END_DTTM >= TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
AND		ROWNUM = 1

mapper.update:
/* intmInsrMapper.deleteIntmInsrOrder */
UPDATE 	MSP_INTM_INSR_ORDER
SET    	END_DTTM = #{endDttm}
	   	, IF_TRGT_CD = (CASE WHEN IF_TRGT_CD IN ('Y','N') THEN 'C' ELSE IF_TRGT_CD END)
       	, RVISN_ID = 'BATCH'
       	, RVISN_DTTM = SYSDATE
WHERE  	CONTRACT_NUM = #{contractNum}
AND    	INSR_PROD_CD = #{insrProdCd}
AND	   	STRT_DTTM = #{strtDttm}
AND		TO_DATE(END_DTTM, 'YYYYMMDDHH24MISS') >= TRUNC(SYSDATE)
AND    	IF_TRGT_CD != 'S'
AND		NOT EXISTS 
		(
			SELECT 	1
			FROM	MSP_JUO_FEATURE_INFO
			WHERE	CONTRACT_NUM = #{contractNum}
			AND		SOC = #{insrProdCd}
			AND		EFFECTIVE_DATE = #{strtDttm}
			AND		TO_DATE(EXPIRATION_DATE,'YYYYMMDDHH24MISS') >= TRUNC(SYSDATE)
		)

/* intmInsrMapper.completeIntmInsrOrder */
UPDATE MSP_INTM_INSR_ORDER
SET    IF_TRGT_CD = 'S'
       , RVISN_ID = 'BATCH'
       , RVISN_DTTM = SYSDATE
WHERE  CONTRACT_NUM = #{contractNum}
AND    INSR_PROD_CD = #{insrProdCd}
AND    STRT_DTTM = #{strtDttm}
AND    IF_TRGT_CD = 'Y'

/* intmInsrMapper.completeIntmInsrCanInfo */
UPDATE	MSP_INTM_INSR_CAN_INFO
SET		PROC_YN = 'Y'
		, PROC_DT = SYSDATE			
		, RSLT_CD = #{rsltCd}

		, RSLT_MSG = #{rsltMsg}

WHERE	INSR_CAN_NUM = #{seqNum}

/* intmInsrMapper.deleteIntmInsrMember */
UPDATE  MSP_INTM_INSR_MEMBER
SET     INSR_STAT_CD = '2'


				, CAN_RSLT_CD = 'EXP'


	      		, END_DTTM = #{endDttm}
        		, CAN_RSLT_CD = DECODE(INSR_STAT_CD, '1', 'REQ', CAN_RSLT_CD)


        , RVISN_ID = 'BATCH'
        , RVISN_DTTM = SYSDATE
WHERE   INSR_MEMBER_NUM = #{insrMemberNum}
AND		INSR_STAT_CD IN ('0','1')

/* intmInsrMapper.updateIntmInsrMember */
UPDATE  MSP_INTM_INSR_MEMBER
SET     CUST_NM = #{custNm}
        , CTN = #{ctn}
        , BIRTH_DT = #{birthDt}
        , RVISN_ID = 'BATCH'
        , RVISN_DTTM = SYSDATE
WHERE   INSR_MEMBER_NUM = #{insrMemberNum}

