/* intmInsrMapper.updateIntmInsrCmpnMember */
UPDATE  MSP_INTM_INSR_MEMBER
SET     INSR_MNGM_NO = #{insrMngmNo}


        		, RMN_CMPN_AMT = #{rmnCmpnAmt}
        		, INSR_STAT_CD = '0'
				, CAN_RSLT_CD = 'TOL'


	      		, RMN_CMPN_AMT = #{rmnCmpnLmtAmt}

	      			, INSR_STAT_CD = '0'
	      			, CAN_RSLT_CD = 'LTL'



        , RVISN_ID = 'BATCH'
        , RVISN_DTTM = SYSDATE
WHERE   CONTRACT_NUM = #{contractNum}
AND     INSR_PROD_CD = #{insrProdCd}
AND		INSR_STAT_CD = '1'
AND     END_DTTM >= TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')

