/* intmInsrMapper.completeIntmInsrCanRetry */
UPDATE	MSP_INTM_INSR_CAN_INFO_TEMP
SET		PROC_YN = 'Y'
, PROC_DT = SYSDATE
, RSLT_CD = #{rsltCd}

	, RSLT_MSG = #{rsltMsg}

WHERE	INSR_CAN_NUM = #{seqNum}

/* intmInsrMapper.updateIntmInsrReady */
UPDATE 	MSP_INTM_INSR_READY
SET		PROC_CD = 'Y'
		, PROC_DT = SYSDATE
WHERE	PROC_CD = 'N'
AND		WORK_CD = #{workCd, jdbcType=VARCHAR}
AND		CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}
AND		INSR_PROD_CD = #{insrProdCd, jdbcType=VARCHAR}
AND		STRT_DTTM = #{strtDttm, jdbcType=VARCHAR}
AND		END_DTTM = #{endDttm, jdbcType=VARCHAR}
AND		REQ_IN_DAY = #{reqInDay, jdbcType=VARCHAR}
